def ask_questions(sentence_retriever, query_list, similarity_threshold=0, filter_fn=lambda x: x):
	classification_dict_gen = sentence_retriever.retrieve(
		query_list=query_list, 
		similarity_threshold=similarity_threshold, 
		without_context=True, 
		top_k=None,
	)
	classification_dict_gen = (
		islice(
			filter(
				filter_fn, 
				unique_everseen(
					answer_iter, 
					key=lambda x: x['doc']
				)
			), 
			OQA_OPTIONS['answer_horizon']
		)
		for answer_iter in classification_dict_gen
	)
	return {
		question: [
			{
				'confidence': answer['similarity'],
				'sentence': answer['doc'], 
				'extra_info': [(None,PAGE_ID_PREDICATE,answer['id'][0])],
			}
			for answer in answer_iter
		]
		for question, answer_iter in zip(query_list, classification_dict_gen)
	}

def generate_macroplan(question, computed_answer_dict, extra_questions=0):
	if question in computed_answer_dict:
		question_answer_dict = {question: computed_answer_dict[question]}
	else:
		question_answer_dict = ask_questions(sentence_retriever, [question], similarity_threshold=0)
		computed_answer_dict.update(question_answer_dict)
	
	if extra_questions:
		related_question_list = []
		#######################################
		oqa_options = dict(OQA_OPTIONS)
		oqa_options['keep_the_n_most_similar_concepts'] = 1
		related_concept_uri_label_list = get_related_concepts(word_retriever, [question], with_cache=True, **oqa_options)
		related_concept_uri_label_list = sorted(related_concept_uri_label_list, key=lambda x: len(x[-1]))
		concept_uri_list, concept_label_list = zip(*word_retriever.remove_similar_labels(
			related_concept_uri_label_list, 
			threshold=label_max_similarity_threshold, 
			key=lambda x: x[-1].casefold(),
			without_context=True,
			with_cache=True,
		))
		print(question, '//', concept_label_list, '//', concept_uri_list)
		#######################################
		new_sentence_retriever = SentenceRetriever(SENTENCE_RETRIEVER_OPTIONS)
		new_sentence_retriever.load_cache(os.path.join(cache_path,'adaptive_qa_embedder-clause_amr_edu.pkl.sentence_retriever.pkl'))
		related_question_list += get_most_similar_questions(
			new_sentence_retriever, qa_dict_list,
			question, 
			top_k=top_k_most_related_questions, 
			max_question_length=float('inf'), 
			question_to_input_min_similarity_threshold=question_to_input_min_similarity_threshold,
			question_to_question_max_similarity_threshold=OQA_OPTIONS['answer_to_answer_max_similarity_threshold'],
			with_cache=True,
		)
		new_sentence_retriever.store_cache(os.path.join(cache_path,'adaptive_qa_embedder-clause_amr_edu.pkl.sentence_retriever.pkl'))
		#######################################
		what_question_template = 'What is {X}?'
		related_question_list += (
			what_question_template.format(X=concept_label) 
			for concept_label in concept_label_list
		)
		#######################################
		related_question_list = list(unique_everseen(related_question_list, key=lambda x: x.casefold()))
		missing_related_question_list = list(filter(lambda x: x not in computed_answer_dict, related_question_list))
		if missing_related_question_list:
			computed_answer_dict.update(ask_questions(
				sentence_retriever,
				missing_related_question_list, 
				similarity_threshold=OQA_OPTIONS['answer_pertinence_threshold']
			))
		extra_question_answer_dict = {}
		for q in related_question_list:
			a_list = computed_answer_dict[q]
			if a_list:
				extra_question_answer_dict[q] = a_list
		extra_question_answer_dict = minimise_question_answer_dict(
			merge_duplicated_answers(extra_question_answer_dict)
		)
		extra_question_answer_items = extra_question_answer_dict.items()
		extra_question_answer_items = filter(lambda x: x[-1], extra_question_answer_items)
		extra_question_answer_items = sorted(extra_question_answer_items, key=lambda x: x[-1][0]['confidence'], reverse=True)
		extra_question_answer_items = islice(extra_question_answer_items, extra_questions)
		extra_question_answer_dict = dict(extra_question_answer_items)
		print(question, '//', list(extra_question_answer_dict.keys()))
		question_answer_dict.update(extra_question_answer_dict)
	else:
		extra_question_answer_dict = None
	return question_answer_dict, extra_question_answer_dict

def get_page_id(x):
	return next(map(lambda z: z[-1], filter(lambda y: y[1]==PAGE_ID_PREDICATE, x)), None)

def build_answer_text(s_p):
	s,p = s_p
	p_str = ''
	if p:
		p = str(p)
		p_str = f"(pp. {p})" if '-' in p else f"(p. {p})"
	return s + ' ' + p_str
	
def surface_explanation(question_answer_dict, prompt, prompt_tokens, experiment_key, frequency_dict, extra_question_answer_dict):
	# print('question_answer_dict', json.dumps(question_answer_dict, indent=4))
	############################################
	if question_answer_dict:
		## The answers contained in other answers (even if from other questions) are replaced with the containing answer.
		## The answers that could be assigned to several questions are given to the question with the highest estimated pertinence.
		# question_answer_dict = {question: list(flatten(question_answer_dict.values()))}
		# question_answer_dict = minimise_question_answer_dict(merge_duplicated_answers(question_answer_dict))
		# question_answer_dict = merge_duplicated_answers(question_answer_dict)
		
		explanation_text_list = []
		tokens_count = prompt_tokens
		for related_question, answer_dict_list in question_answer_dict.items():
			sentence_list = [x['sentence'] for x in answer_dict_list]
			if not sentence_list:
				continue
			page_id_list = [get_page_id(x['extra_info']) for x in answer_dict_list] if textbook else [None]*len(answer_dict_list)
			answers_text = '- '+'\n- '.join(map(build_answer_text, zip(sentence_list,page_id_list)))
			question_answer_text = related_question+'\n'+answers_text
			qa_tokens_count = count_tokens(question_answer_text)
			if tokens_count + qa_tokens_count <= max_tokens_count[model]:
				explanation_text_list.append(question_answer_text)
				tokens_count += qa_tokens_count
			else:
				break # the generative AI cannot process any more questions
			
		yai_explanation = '\n\n'.join(explanation_text_list)

		# print('#'*20)
		# print(yai_explanation)
		# print('@'*20)
		
		frequency_dict[f'explanation_{experiment_key}'] = sentence_retriever.instruct_model(
			[
				prompt.format(
					textbook=textbook, 
					topic=question, 
					contents=yai_explanation.strip(), 
					body=stackoverflow_questions_dict[task][question]['body']
				)
			], 
			**SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']
		)[0]
		frequency_dict[f'info_{experiment_key}'] = {
			'processed_extra_questions_count': len(explanation_text_list)-1,
			'extra_questions': list(extra_question_answer_dict.keys()) if extra_question_answer_dict else [],
			'prompt_tokens': prompt_tokens,
			'rag_context_tokens': count_tokens(yai_explanation),
			'output_tokens': count_tokens(frequency_dict[f'explanation_{experiment_key}']),
		}
		print(question, frequency_dict[f'explanation_{experiment_key}'])
		print('rag_context_tokens:', frequency_dict[f'info_{experiment_key}']['rag_context_tokens'])
		print('prompt_tokens:', prompt_tokens)
	else:
		frequency_dict[f'explanation_{experiment_key}'] = ''
	# input()

def generate_explanation(prompt, experiment_key, question, topic_frequency_dict, computed_answer_dict, extra_questions=0):
	frequency_dict = topic_frequency_dict[question]
	if experiment_key not in model_name_dict:
		return False
	if not rebuild_explanations and frequency_dict.get(f'explanation_{experiment_key}',None):
		return False
	question_answer_dict, extra_question_answer_dict = generate_macroplan(question, computed_answer_dict, extra_questions=extra_questions)
	if not question_answer_dict:
		return False
	prompt_tokens = count_tokens(prompt) + count_tokens(textbook) + count_tokens(question)
	if output_type=='question':
		prompt_tokens += count_tokens(stackoverflow_questions_dict[task][question]['body'])
	surface_explanation(question_answer_dict, prompt, prompt_tokens, experiment_key, frequency_dict, extra_question_answer_dict)
	return True

