def gpt_cache_key(instruction): 
	key_values = [instruction]
	if SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['model'] != 'gpt-4o':
		key_values.append(SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['model'])
	if SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['temperature'] != 1:
		key_values.append(SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['temperature'])
	if SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['top_p'] != 1:
		key_values.append(SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['top_p'])
	return '_'.join(map(str,key_values))

def process_topics(topics, prompt_format, cache_key_suffix, topic_frequency_dict):
	client = None
	thread_n_run_dict = {}

	has_run_prompt = False
	for so_topic in topics:
		instruction = prompt_format.format(textbook=textbook, topic=so_topic, body=stackoverflow_questions_dict[task][so_topic]['body'])
		if not assistant_gpt_cache.get(gpt_cache_key(instruction), None):
			if client is None:
				client = OpenAI(api_key=SENTENCE_RETRIEVER_OPTIONS['generative_ai_options']['api_key'])
			thread_n_run_dict[so_topic] = create_thread_and_run(client, assistant_id, instruction, SENTENCE_RETRIEVER_OPTIONS)

	for so_topic in tqdm(topics, desc=f'Generating {cache_key_suffix} GPT explanations'):
		frequency_dict = topic_frequency_dict[so_topic]
		instruction = prompt_format.format(textbook=textbook, topic=so_topic, body=stackoverflow_questions_dict[task][so_topic]['body'])
		if so_topic in thread_n_run_dict:
			thread, run = thread_n_run_dict[so_topic]
			run = wait_on_run(client, run, thread)
			messages = list(get_response(client, thread))
			has_run_prompt = True
			explanation_gpt = messages[-1].content[0].text.value if len(messages) == 2 else ''
			prompt_tokens = count_tokens(instruction)
			# print(run.usage, prompt_tokens)
			frequency_dict[f'info_{cache_key_suffix}'] = {
				'prompt_tokens': prompt_tokens,
				'rag_context_tokens': run.usage.prompt_tokens-prompt_tokens,
				'output_tokens': count_tokens(explanation_gpt),
			}
			print('rag_context_tokens:', frequency_dict[f'info_{cache_key_suffix}']['rag_context_tokens'])
			print('prompt_tokens:', prompt_tokens)
			frequency_dict[f'explanation_{cache_key_suffix}'] = explanation_gpt
			assistant_gpt_cache[gpt_cache_key(instruction)] = explanation_gpt
		else:
			frequency_dict[f'explanation_{cache_key_suffix}'] = assistant_gpt_cache.get(gpt_cache_key(instruction), None)
	if has_run_prompt:
		create_cache(default_cache_path+'.assistant_gpt_cache.pkl', lambda: assistant_gpt_cache)
	return has_run_prompt

