def get_atomic_facts_from_kg_manager(kg_manager):
	atomic_fact_label_iter = (
		sentence
		for source_sentence_uri in flatten(kg_manager.source_span_dict.values())
		for sentence in kg_manager.source_label_dict[source_sentence_uri]
	)
	atomic_fact_label_iter = unique_everseen(atomic_fact_label_iter)
	atomic_fact_label_iter = filter(contains_verb, atomic_fact_label_iter) # keep only clauses containing a verb
	atomic_fact_label_list = list(atomic_fact_label_iter)
	return list(filter(
		lambda x: not any(map(lambda y: x in y and x != y, atomic_fact_label_list)), 
		atomic_fact_label_list
	))

def build_support_dicts(atomic_fact_label_list, sentence_retriever):
	atomic_fact_support_dict = {}
	support_dict = {}
	for atomic_fact_label in tqdm(atomic_fact_label_list, desc='Checking facts'):
		supported_fact_list = list(list(sentence_retriever.retrieve([atomic_fact_label], similarity_threshold=0, without_context=True, top_k=1))[0])
		supported_fact_label = supported_fact_list[0]['doc']
		support_score = supported_fact_list[0]['similarity']
		if support_score >= fact_score_similarity_threshold:
			print(atomic_fact_label, '//', supported_fact_label, '//', support_score)
		atomic_fact_support_dict[atomic_fact_label] = support_score
		support_dict[supported_fact_label] = max(support_score, support_dict.get(supported_fact_label,0))

	atomic_fact_support_dict = remove_redundant_facts_from_fact_dict(atomic_fact_support_dict)
	support_dict = remove_redundant_facts_from_fact_dict(support_dict)
	return atomic_fact_support_dict, support_dict

def build_kg_manager(input_doc, so_topic):
	if not input_doc:
		return None
	answer_kg = load_or_create_cache(
		os_path.join(explanation_kg_path,f'{model}-{get_str_uid(so_topic)}-{get_str_uid(input_doc)}.graph.pkl'), 
		lambda: KnowledgeGraphExtractor(GRAPH_BUILDER_OPTIONS).set_content_list([input_doc], **GRAPH_CLEANING_OPTIONS).build(**GRAPH_EXTRACTION_OPTIONS)
	)
	if not answer_kg:
		return None
	return KnowledgeGraphManager(KG_MANAGER_OPTIONS, answer_kg)

def set_sentence_retriever_documents(kg_manager, sentence_retriever):
	triplet_uri_sentence_list = list(unique_everseen(
		(
			(source_sentence_uri,sentence)
			for source_sentence_uri in flatten(kg_manager.source_span_dict.values())
			for sentence in kg_manager.source_label_dict[source_sentence_uri]
			if contains_verb(sentence)
		), 
		key=lambda x: x[-1]
	))
	triplet_list, triplet_text_list = zip(*filter(lambda x: not any(map(lambda y: x[-1] in y[-1] and x[-1] != y[-1], triplet_uri_sentence_list)), triplet_uri_sentence_list))
	sentence_retriever.set_documents(triplet_list, triplet_text_list)
	return len(triplet_text_list)

