for so_topic in tqdm(stackoverflow_questions[task], desc='Computing FAct Scores'):
	frequency_dict = topic_frequency_dict[so_topic]
	for model in model_name_dict.keys():
		doc_content = frequency_dict[f'explanation_{model}']
		if not doc_content:
			continue
		v = frequency_dict[f'scores_{model}']
		v['fact_score_fuzzy'] = float(np.mean(v['fact_supporting']))
		v['supporting_facts'] = int(np.sum(v['fact_supporting'] >= fact_score_similarity_threshold))
		v['fact_score'] = v['supporting_facts']/len(v['fact_supporting'])
		# v['fact_recall'] = v['supporting_facts']/max_number_of_supported_facts
		# v['fact_f1'] = 2*v['fact_score']*v['fact_recall']/(v['fact_score']+v['fact_recall'])
		v['supporting_facts_labels'] = [
			k
			for k,v in zip(v['fact_supporting_labels'], v['fact_supporting'].tolist()) 
			if v >= fact_score_similarity_threshold
		]

		v['supported_facts'] = int(np.sum(v['fact_supported'] >= fact_score_similarity_threshold))
		v['supported_facts_labels'] = [
			k
			for k,v in zip(v['fact_supported_labels'], v['fact_supported'].tolist()) 
			if v >= fact_score_similarity_threshold
		]
		v['explanation_words'] = len(doc_content.split(' '))
